import re

class TrieNode:
    def __init__(self):
        self.children = {}
        self.replacement_value = None

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word, replacement):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.replacement_value = replacement

    def get_replacement(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                return None
            node = node.children[char]
        return node.replacement_value

def replace_words_using_trie(text, replacements_dict):
    trie = Trie()
    for original, replacement in replacements_dict.items():
        trie.insert(original.lower(), replacement)

    result_parts = []
    last_idx = 0

    for match in re.finditer(r'\b\w+\b', text):
        result_parts.append(text[last_idx:match.start()])

        original_word = match.group(0)
        replacement = trie.get_replacement(original_word.lower())

        if replacement:
            if original_word.isupper():
                result_parts.append(replacement.upper())
            elif original_word.istitle():
                result_parts.append(replacement.capitalize())
            else:
                result_parts.append(replacement)
        else:
            result_parts.append(original_word)

        last_idx = match.end()

    result_parts.append(text[last_idx:])

    return "".join(result_parts)
